                            <script>
                                document.addEventListener('DOMContentLoaded', function () {
                                    // بروزرسانی تعداد در مینی کارت
                                    function updateMiniCartQuantity(cartId, quantity) {
                                        fetch(`/cart/update/${cartId}`, {
                                            method: 'PUT',
                                            headers: {
                                                'Content-Type': 'application/json',
                                                'X-CSRF-TOKEN': '{{ csrf_token() }}',
                                                'Accept': 'application/json'
                                            },
                                            body: JSON.stringify({quantity: quantity})
                                        })
                                            .then(response => response.json())
                                            .then(data => {
                                                if (data.success) {
                                                    location.reload();
                                                } else {
                                                    alert(data.message || 'خطا در بروزرسانی');
                                                    location.reload();
                                                }
                                            });
                                    }

                                    // حذف از مینی کارت
                                    function removeFromMiniCart(cartId) {
                                        if (confirm('آیا از حذف این محصول اطمینان دارید؟')) {
                                            fetch(`/cart/remove/${cartId}`, {
                                                method: 'DELETE',
                                                headers: {
                                                    'X-CSRF-TOKEN': '{{ csrf_token() }}',
                                                    'Accept': 'application/json'
                                                }
                                            })
                                                .then(response => response.json())
                                                .then(data => {
                                                    if (data.success) {
                                                        location.reload();
                                                    }
                                                });
                                        }
                                    }

                                    // دکمه + در مینی کارت
                                    document.querySelectorAll('.mini-cart-plus').forEach(btn => {
                                        btn.addEventListener('click', function (e) {
                                            e.preventDefault();
                                            let id = this.getAttribute('data-id');
                                            let input = document.querySelector(`.mini-cart-quantity[data-id="${id}"]`);
                                            if (input) {
                                                let newVal = parseInt(input.value) + 1;
                                                let max = parseInt(input.getAttribute('max'));
                                                if (newVal <= max) {
                                                    updateMiniCartQuantity(id, newVal);
                                                } else {
                                                    alert('تعداد وارد شده بیشتر از موجودی انبار است');
                                                }
                                            }
                                        });
                                    });

                                    // دکمه - در مینی کارت
                                    document.querySelectorAll('.mini-cart-minus').forEach(btn => {
                                        btn.addEventListener('click', function (e) {
                                            e.preventDefault();
                                            let id = this.getAttribute('data-id');
                                            let input = document.querySelector(`.mini-cart-quantity[data-id="${id}"]`);
                                            if (input) {
                                                let newVal = parseInt(input.value) - 1;
                                                if (newVal >= 1) {
                                                    updateMiniCartQuantity(id, newVal);
                                                }
                                            }
                                        });
                                    });

                                    // دکمه حذف در مینی کارت
                                    document.querySelectorAll('.remove-item').forEach(btn => {
                                        btn.addEventListener('click', function (e) {
                                            e.preventDefault();
                                            let id = this.getAttribute('data-id');
                                            removeFromMiniCart(id);
                                        });
                                    });
                                });
                            </script>
